-- Quiz Personal Branding — 8 quiz de module + 1 quiz de validation finale.-- Généré par scripts/generate_pb_quizzes.py à partir du doc client Lovable.-- Même modèle que Muslim Mindset : quiz attachés aux chapitres, shuffle auto via import_quiz_from_json.SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 1 — Fondements & Philosophie", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quelle est la meilleure définition du personal branding ?", "options": ["Poster des selfies sur Instagram", "L'art de construire et gérer l'image que le monde perçoit de vous", "Créer un logo et une charte graphique", "Avoir beaucoup de followers"], "correct_index": 1, "explication": "Le personal branding est l'art de construire et gérer intentionnellement l'image que le monde perçoit de vous."}, {"question": "Le personal branding est réservé aux célébrités et influenceurs.", "options": ["Vrai", "Faux"], "correct_index": 1, "explication": "Tout professionnel en a besoin. Le personal branding n'est pas réservé aux célébrités."}, {"question": "Quel pourcentage des décisions d'achat se fait sur la base de la confiance ?", "options": ["50%", "74%", "95%", "100%"], "correct_index": 2, "explication": "95% des décisions d'achat se font sur la base de la confiance — le personal branding construit cette confiance."}, {"question": "Quels sont les 3 piliers fondamentaux du personal branding ?", "options": ["Contenu, Audience, Revenus", "Identité, Visibilité, Crédibilité", "Logo, Couleurs, Typographie", "Stratégie, Exécution, Monétisation"], "correct_index": 1, "explication": "Les 3 piliers sont : Identité (qui vous êtes), Visibilité (être vu), Crédibilité (être cru et respecté)."}, {"question": "Sans identité, votre contenu n'a pas d'âme. Sans visibilité, personne ne vous trouve. Sans crédibilité...", "options": ["Personne ne vous achète", "Personne ne vous like", "Personne ne vous comprend", "Personne ne vous copie"], "correct_index": 0, "explication": "Sans crédibilité, personne ne vous achète. Les 3 piliers doivent avancer ensemble."}, {"question": "Quel est l'ordre correct de la pyramide du personal branding (du bas vers le haut) ?", "options": ["Contenu → Communauté → Monétisation → Clarté", "Clarté → Positionnement → Contenu → Communauté → Autorité → Monétisation", "Monétisation → Autorité → Contenu → Positionnement", "Visibilité → Crédibilité → Identité → Monétisation"], "correct_index": 1, "explication": "La pyramide se construit du bas vers le haut : Clarté → Positionnement → Contenu → Communauté → Autorité → Monétisation."}, {"question": "Quelle est l'erreur classique avec la pyramide du personal branding ?", "options": ["Publier trop de contenu", "Essayer de monétiser avant d'avoir construit les 4 premières étapes", "Ne pas avoir de logo", "Être sur trop de plateformes"], "correct_index": 1, "explication": "L'erreur classique est d'essayer de monétiser avant d'avoir construit les étapes fondamentales."}, {"question": "Le personal branding est de la manipulation.", "options": ["Vrai", "Faux"], "correct_index": 1, "explication": "Le personal branding n'est PAS de la manipulation. C'est l'amplification stratégique de ce que vous êtes réellement."}, {"question": "Les personnes avec une marque forte gagnent combien de plus que leurs pairs ?", "options": ["5 à 10%", "10 à 15%", "20 à 30%", "50 à 60%"], "correct_index": 2, "explication": "Les personnes avec une marque forte gagnent 20 à 30% de plus que leurs pairs sans marque."}, {"question": "Quel pourcentage des consommateurs fait davantage confiance à un expert reconnu qu'à une publicité ?", "options": ["45%", "58%", "74%", "91%"], "correct_index": 2, "explication": "74% des consommateurs font davantage confiance à un expert reconnu qu'à une publicité."}, {"question": "Que représente le sommet de la pyramide du personal branding ?", "options": ["L'autorité", "La communauté", "La monétisation", "Le contenu"], "correct_index": 2, "explication": "Le sommet de la pyramide est la monétisation : transformer votre marque en revenus."}, {"question": "Le personal branding est un actif qui...", "options": ["Perd de la valeur avec le temps", "Prend de la valeur avec le temps", "Reste stable", "N'a aucune valeur économique"], "correct_index": 1, "explication": "Le personal branding est un actif qui prend de la valeur avec le temps."}, {"question": "Dans le cas d'Idriss (consultant RH), quel était son score d'identité ?", "options": ["2/10", "4/10", "6/10", "8/10"], "correct_index": 1, "explication": "Idriss avait un score d'identité de 4/10 car il n'avait pas de niche claire."}, {"question": "Quelle était l'action prioritaire recommandée pour Idriss ?", "options": ["Poster du contenu viral", "Définir son positionnement avant de poster", "Créer un logo professionnel", "Acheter de la publicité"], "correct_index": 1, "explication": "L'action prioritaire était de définir son positionnement avant de poster quoi que ce soit."}, {"question": "Le personal branding c'est poster pour l'ego ou le like.", "options": ["Vrai", "Faux"], "correct_index": 1, "explication": "C'est de la vanité. Le personal branding est une promesse de valeur claire, pas de la vanité."}, {"question": "Dans l'économie du créateur, quel est votre plus grand actif ?", "options": ["Votre produit", "Votre audience", "Votre logo", "Votre compte bancaire"], "correct_index": 1, "explication": "Dans l'économie du créateur, votre audience est votre plus grand actif."}, {"question": "Le personal branding est une promesse de valeur claire faite à...", "options": ["Tout le monde", "Une audience précise", "Vos amis", "Les algorithmes"], "correct_index": 1, "explication": "C'est une promesse de valeur claire faite à une audience précise."}, {"question": "Un personal brand fort vous protège contre...", "options": ["Les impôts", "L'obsolescence professionnelle", "Les critiques en ligne", "La concurrence directe uniquement"], "correct_index": 1, "explication": "Un personal brand fort vous protège contre l'obsolescence professionnelle."}, {"question": "Quelle affirmation est VRAIE sur le personal branding ?", "options": ["C'est un masque pour paraître mieux", "C'est la réputation que vous cultivez intentionnellement", "C'est réservé aux entrepreneurs", "C'est uniquement digital"], "correct_index": 1, "explication": "Le personal branding est la réputation que vous cultivez intentionnellement."}, {"question": "Votre personal brand existe déjà — la question est de savoir si vous le...", "options": ["Monétisez", "Contrôlez", "Copiez", "Ignorez"], "correct_index": 1, "explication": "Votre personal brand existe déjà — la question est de savoir si vous le contrôlez."}], "chapitre_id": "e16e0cdd-482e-42bd-9e91-b515db8cede9"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 2 — Identité & Positionnement", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Combien de questions fondatrices faut-il se poser avant de créer du contenu ?", "options": ["3", "5", "7", "10"], "correct_index": 1, "explication": "Il y a 5 questions fondatrices : Qui suis-je ? Pour qui ? Pourquoi moi ? Avec quoi ? Vers où ?"}, {"question": "Que signifie 'Ikigai' en japonais ?", "options": ["Succès financier", "Raison d'être", "Force intérieure", "Équilibre de vie"], "correct_index": 1, "explication": "L'Ikigai est un concept japonais qui signifie 'raison d'être'."}, {"question": "L'Ikigai de marque est la zone où combien de cercles se superposent ?", "options": ["2", "3", "4", "5"], "correct_index": 2, "explication": "4 cercles : ce que vous aimez, ce pour quoi vous êtes bon, ce dont le monde a besoin, ce pour quoi vous pouvez être payé."}, {"question": "Sans positionnement clair, vous êtes...", "options": ["Unique", "Interchangeable", "Visible", "Populaire"], "correct_index": 1, "explication": "Sans positionnement clair, vous êtes interchangeable. Interchangeable = invisible."}, {"question": "Combien d'axes de différenciation existent dans le positionnement ?", "options": ["3", "4", "6", "8"], "correct_index": 2, "explication": "Il existe 6 axes : spécialisation, histoire, méthode, valeurs, public cible, style."}, {"question": "Quelle est la formule de positionnement en une phrase ?", "options": ["Je suis expert en [domaine]", "J'aide [cible] à [résultat] grâce à [méthode], même si [contrainte]", "Mon produit est le meilleur du marché", "Je vends [produit] à [prix]"], "correct_index": 1, "explication": "La formule est : J'aide [cible précise] à [résultat désiré] grâce à [méthode unique], même si [objection/contrainte]."}, {"question": "Les archétypes de marque sont inspirés de quel penseur ?", "options": ["Freud", "Maslow", "Carl Jung", "Aristote"], "correct_index": 2, "explication": "Les archétypes de marque sont inspirés de Carl Jung."}, {"question": "Combien d'archétypes devriez-vous combiner pour votre marque ?", "options": ["1 seul", "2 (principal + secondaire)", "3 minimum", "Le plus possible"], "correct_index": 1, "explication": "Combinez 2 archétypes (principal + secondaire) pour plus de profondeur."}, {"question": "L'archétype du SAGE se caractérise par...", "options": ["Le courage et le défi", "La vérité, le savoir et la clarté", "L'humour et la légèreté", "La rupture et la révolution"], "correct_index": 1, "explication": "Le Sage : vérité, savoir, clarté. Ton pédagogique. Vous éduquez et déconstruisez."}, {"question": "L'archétype du REBELLE se caractérise par...", "options": ["L'empathie et l'accompagnement", "L'innovation et la vision", "La rupture, la liberté, la révolution", "Le succès et la victoire"], "correct_index": 2, "explication": "Le Rebelle : rupture, liberté, révolution. Vous challengez l'ordre établi."}, {"question": "La question 'Pour qui ?' dans les 5 questions fondatrices correspond à...", "options": ["Votre mission", "Votre avatar idéal", "Votre méthode", "Votre légitimité"], "correct_index": 1, "explication": "'Pour qui ?' = votre avatar idéal, son problème, sa transformation rêvée."}, {"question": "La question 'Avec quoi ?' dans les 5 questions fondatrices correspond à...", "options": ["Vos outils techniques", "Votre méthode/approche/système unique", "Votre budget", "Votre réseau"], "correct_index": 1, "explication": "'Avec quoi ?' = votre méthode, approche ou système unique. Votre signature."}, {"question": "Dans le cas de Sara, quel était son positionnement AVANT ?", "options": ["Coach en reconversion pour cadres", "Coach professionnelle qui aide les gens à trouver leur voie", "Consultante RH spécialisée", "Mentor en leadership"], "correct_index": 1, "explication": "Avant : 'Je suis coach professionnelle. J'aide les gens à trouver leur voie.' — trop vague."}, {"question": "Comment s'appelle la méthode de Sara après positionnement ?", "options": ["Méthode IMPACT", "Méthode PIVOT", "Méthode FOCUS", "Méthode ATLAS"], "correct_index": 1, "explication": "Sara a créé la Méthode PIVOT (90 jours, 3 étapes, sans démissionner avant d'avoir signé)."}, {"question": "Lequel de ces éléments N'EST PAS un des 4 cercles de l'Ikigai ?", "options": ["Ce que vous aimez faire", "Ce pour quoi vous êtes bon", "Ce qui est tendance sur les réseaux", "Ce dont le monde a besoin"], "correct_index": 2, "explication": "Les 4 cercles sont : passion, compétence, besoin du monde, rémunération. Les tendances ne font pas partie de l'Ikigai."}, {"question": "L'axe de différenciation 'LA MÉTHODE' consiste à...", "options": ["Copier la méthode d'un concurrent", "Créer un système unique avec un nom propre", "Utiliser les dernières technologies", "Avoir le plus de certifications"], "correct_index": 1, "explication": "La méthode = un système unique avec un nom propre (Méthode X)."}, {"question": "La cohérence bat la variété dans le choix des archétypes.", "options": ["Vrai", "Faux"], "correct_index": 0, "explication": "Choisissez 2 archétypes et restez-y. La cohérence bat la variété."}, {"question": "L'archétype du GUIDE/MENTOR se caractérise par...", "options": ["L'innovation et la vision", "L'empathie et l'accompagnement", "L'humour et la légèreté", "L'audace et la disruption"], "correct_index": 1, "explication": "Le Guide/Mentor : empathie, accompagnement. Vous mettez l'audience au centre."}, {"question": "Quel est l'objectif de la question 'Vers où ?' ?", "options": ["Définir votre prochain post", "Définir votre mission long terme et votre impact à 5 ans", "Choisir votre prochaine plateforme", "Fixer votre prix"], "correct_index": 1, "explication": "'Vers où ?' = votre mission long terme. Quel impact voulez-vous avoir dans 5 ans ?"}, {"question": "Les 5 questions fondatrices sont comparées à...", "options": ["Un business plan", "Un GPS de votre marque", "Un CV", "Un portfolio"], "correct_index": 1, "explication": "Les 5 questions fondatrices sont le GPS de votre marque. Sans elles, tout le reste est aléatoire."}], "chapitre_id": "615f8250-9a10-4e68-8e68-649932b0669e"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 3 — Identité Visuelle & Signature", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "En combien de millisecondes votre identité visuelle communique-t-elle votre positionnement ?", "options": ["500", "200", "50", "1000"], "correct_index": 2, "explication": "L'identité visuelle communique votre positionnement en 50 millisecondes."}, {"question": "Une identité cohérente augmente la reconnaissance de marque de combien ?", "options": ["30%", "50%", "80%", "120%"], "correct_index": 2, "explication": "Une identité cohérente augmente la reconnaissance de marque de 80%."}, {"question": "Combien d'éléments composent l'identité visuelle ?", "options": ["3", "4", "6", "8"], "correct_index": 2, "explication": "6 éléments : photo de profil, palette de couleurs, typographie, style visuel, templates/format, logo/signature."}, {"question": "La couleur ROUGE symbolise...", "options": ["Confiance et expertise", "Énergie, urgence, passion, audace", "Luxe et créativité", "Croissance et équilibre"], "correct_index": 1, "explication": "Rouge = énergie, urgence, passion, audace. Idéal pour coach sportif, motivation."}, {"question": "La couleur BLEU symbolise...", "options": ["Énergie et passion", "Luxe et spiritualité", "Confiance, expertise, calme, fiabilité", "Créativité et enthousiasme"], "correct_index": 2, "explication": "Bleu = confiance, expertise, calme, fiabilité. Idéal pour finance, tech, consulting."}, {"question": "La couleur NOIR symbolise...", "options": ["Nature et équilibre", "Luxe, élégance, autorité", "Optimisme et succès", "Énergie et urgence"], "correct_index": 1, "explication": "Noir = luxe, élégance, autorité. Idéal pour positionnement premium, high-ticket."}, {"question": "Quelle est la résolution minimale recommandée pour une photo de profil ?", "options": ["400x400px", "600x600px", "800x800px", "1200x1200px"], "correct_index": 2, "explication": "La résolution minimale recommandée est de 800x800px."}, {"question": "Combien d'adjectifs devez-vous choisir pour définir votre voix de marque ?", "options": ["1", "2", "3", "5"], "correct_index": 2, "explication": "Choisissez 3 adjectifs et appliquez-les à chaque texte publié."}, {"question": "Le brand statement doit contenir combien de mots ?", "options": ["1-3 mots", "5-10 mots", "15-20 mots", "30+ mots"], "correct_index": 1, "explication": "Le brand statement résume votre marque en 5 à 10 mots. Mémorable et unique."}, {"question": "Quelle est la règle pour la palette de couleurs ?", "options": ["Utiliser au moins 5 couleurs", "1 couleur dominante (60-70%), 1-2 secondaires, 1 accent", "Toujours utiliser du bleu", "Changer de couleurs chaque mois"], "correct_index": 1, "explication": "1 couleur dominante (60-70%), 1-2 couleurs secondaires, 1 accent. Pas plus."}, {"question": "Votre photo de profil doit être...", "options": ["Différente sur chaque plateforme", "La même sur toutes les plateformes", "Un logo", "Un avatar cartoon"], "correct_index": 1, "explication": "Même photo = reconnaissance. Cohérente sur toutes les plateformes."}, {"question": "La formule 'Verbe d'action + résultat + identité' sert à créer...", "options": ["Un post Instagram", "Un brand statement", "Un business plan", "Une bio LinkedIn"], "correct_index": 1, "explication": "C'est une des formules créatrices pour votre brand statement."}, {"question": "Dans le cas de Malik, quelles couleurs a-t-il choisies ?", "options": ["Rouge + Blanc", "Bleu foncé + Or", "Vert + Noir", "Violet + Argent"], "correct_index": 1, "explication": "Malik a choisi Bleu foncé (#1A3A6B) + Or (#C8940A). Message : confiance + succès."}, {"question": "Quel résultat Malik a-t-il obtenu après 90 jours ?", "options": ["100 nouveaux followers", "Taux de reconnaissance multiplié par 4", "Première vente réalisée", "10 000 vues sur un post"], "correct_index": 1, "explication": "Résultat après 90 jours : taux de reconnaissance multiplié par 4 sur Instagram."}, {"question": "La couleur VIOLET est idéale pour...", "options": ["Le coaching sportif", "La finance et le consulting", "Le coaching haut de gamme et les créatifs", "La formation et l'éducation"], "correct_index": 2, "explication": "Violet = luxe, créativité, spiritualité. Idéal pour coach haut de gamme, créatif."}, {"question": "Le 'TON' dans la voix de marque fait référence à...", "options": ["Le volume de votre voix", "Formel ou décontracté, sérieux ou humoristique", "La fréquence de publication", "Le type de contenu"], "correct_index": 1, "explication": "Le TON : formel ou décontracté ? Sérieux ou humoristique ?"}, {"question": "La photo de profil est comparée à...", "options": ["Un CV visuel", "Une poignée de main virtuelle", "Un business card", "Un logo"], "correct_index": 1, "explication": "La photo de profil est votre poignée de main virtuelle."}, {"question": "La couleur ORANGE est idéale pour...", "options": ["Le luxe et l'élégance", "La formation, l'éducation, l'entrepreneuriat", "La finance et la tech", "Le bien-être et la nature"], "correct_index": 1, "explication": "Orange = créativité, enthousiasme. Idéal pour formation, éducation, entrepreneuriat."}, {"question": "Un brand statement basé sur la 'Tension/Paradoxe' ressemble à...", "options": ["Expertise éthique. Succès authentique.", "Travailler moins. Gagner plus. Enfin.", "Libère ton potentiel, vis ta mission", "J'aide les entrepreneurs à réussir"], "correct_index": 1, "explication": "Tension/Paradoxe : 'Travailler moins. Gagner plus. Enfin.'"}, {"question": "Votre actif visuel le plus important est...", "options": ["Votre logo", "Votre palette de couleurs", "Votre photo de profil", "Vos templates de posts"], "correct_index": 2, "explication": "Photo de profil : votre actif le plus important. Investissez dans une séance pro."}], "chapitre_id": "289acce1-dc47-4f95-92eb-a44b64b95536"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 4 — Stratégie de Contenu", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quel pourcentage de contenu éducatif est recommandé ?", "options": ["10-15%", "20-25%", "35-40%", "50-60%"], "correct_index": 2, "explication": "Éducatif : 35-40% — démontrer l'expertise avec tips, frameworks, tutoriels."}, {"question": "Le contenu commercial doit représenter quel pourcentage ?", "options": ["5-10%", "15-20%", "30-35%", "40-50%"], "correct_index": 1, "explication": "Commercial : 15-20% — convertir et vendre via témoignages, résultats, offres."}, {"question": "La Phase Semence du Content Compound Interest dure...", "options": ["0-1 mois", "0-3 mois", "3-9 mois", "9-24 mois"], "correct_index": 1, "explication": "Phase Semence (0-3 mois) : peu de résultats visibles, construction des bases."}, {"question": "Combien de thèmes piliers un personal brand efficace doit-il avoir ?", "options": ["1-2", "3-5", "6-8", "10+"], "correct_index": 1, "explication": "3 à 5 thèmes piliers maximum. Rester focusé."}, {"question": "Le repurposing permet de transformer 1 idée en combien de contenus ?", "options": ["3", "5", "10", "20"], "correct_index": 2, "explication": "1 idée = 10 contenus grâce au repurposing."}, {"question": "La régularité bat la qualité.", "options": ["Vrai", "Faux"], "correct_index": 0, "explication": "Un contenu moyen publié régulièrement bat un contenu excellent publié rarement."}, {"question": "La Phase Fruit du Content Compound commence à partir de...", "options": ["1 mois", "3 mois", "9 mois", "24 mois"], "correct_index": 2, "explication": "Phase Fruit (9-24 mois) : l'accélération, le contenu ancien génère de la visibilité."}, {"question": "La plupart des gens abandonnent...", "options": ["Après la première semaine", "Juste avant que l'effet compound commence", "Après avoir gagné de l'argent", "Quand ils ont trop de followers"], "correct_index": 1, "explication": "La plupart des gens abandonnent juste avant que l'effet compound commence."}, {"question": "Le contenu communautaire doit représenter quel pourcentage ?", "options": ["5-10%", "15-20%", "25-30%", "35-40%"], "correct_index": 0, "explication": "Communautaire : 5-10% — engager et fédérer via questions, sondages, UGC."}, {"question": "Dans le calendrier type, quel contenu est recommandé le lundi ?", "options": ["Inspirationnel (reel)", "Éducatif (carousel)", "Commercial (témoignage)", "Entertainment (coulisses)"], "correct_index": 1, "explication": "Lundi : Éducatif (carousel) selon le calendrier type."}, {"question": "Le repurposing d'un article en Thread Twitter/X consiste à...", "options": ["Poster le lien de l'article", "Découper l'article en 10 tweets", "Résumer en 1 tweet", "Publier une capture d'écran"], "correct_index": 1, "explication": "Thread Twitter/X = article découpé en 10 tweets."}, {"question": "Dans le cas de Nour, combien d'heures de création par semaine ?", "options": ["1h", "3h", "5h", "10h"], "correct_index": 1, "explication": "Nour dispose de 3h de création par semaine."}, {"question": "Le contenu inspirationnel vise à...", "options": ["Démontrer l'expertise", "Créer la connexion émotionnelle", "Convertir et vendre", "Engager et fédérer"], "correct_index": 1, "explication": "Inspirationnel (20-25%) : créer la connexion émotionnelle via story, transformation, mindset."}, {"question": "Un 'cluster' de contenu est...", "options": ["Un groupe de followers", "Un ensemble de contenus autour d'un thème pilier", "Un type de publication", "Un format vidéo"], "correct_index": 1, "explication": "Chaque thème pilier devient un cluster — un ensemble de contenus liés."}, {"question": "Quel format de repurposing utilise le point le plus contre-intuitif de l'article ?", "options": ["Newsletter", "Citation visuelle", "Reel / TikTok", "Podcast"], "correct_index": 2, "explication": "Reel / TikTok = le point le plus contre-intuitif de l'article source."}, {"question": "Le contenu entertainment sert à...", "options": ["Vendre des produits", "Retenir et fidéliser", "Démontrer l'expertise", "Construire la crédibilité"], "correct_index": 1, "explication": "Entertainment (10-15%) : retenir et fidéliser via humour, coulisses, débats."}, {"question": "Combien de contenus Nour génère-t-elle par idée ?", "options": ["2-3", "5-6", "10", "15"], "correct_index": 1, "explication": "1 idée par semaine, 5-6 contenus générés par idée pour Nour."}, {"question": "Le content compound fonctionne comme...", "options": ["Un sprint", "Les intérêts composés", "Une loterie", "Un algorithme"], "correct_index": 1, "explication": "Le contenu fonctionne comme les intérêts composés — l'effet s'accumule."}, {"question": "La Phase Racine dure de...", "options": ["0-3 mois", "3-9 mois", "9-24 mois", "24+ mois"], "correct_index": 1, "explication": "Phase Racine (3-9 mois) : premières preuves sociales, premières ventes organiques."}, {"question": "Dans le calendrier type, quel jour est recommandé pour le contenu commercial (témoignage) ?", "options": ["Lundi", "Mercredi", "Vendredi", "Dimanche"], "correct_index": 2, "explication": "Vendredi : Commercial (témoignage) selon le calendrier type. Lundi = éducatif, Mercredi = inspirationnel."}], "chapitre_id": "4c6fef16-6f4f-4da6-99c9-289ae88d0af8"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 5 — Plateformes & Algorithmes", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "La règle d'or des plateformes est...", "options": ["Être sur toutes les plateformes", "Maîtriser UNE plateforme avant d'en ouvrir une deuxième", "Changer de plateforme chaque trimestre", "Publier le même contenu partout"], "correct_index": 1, "explication": "Maîtrisez UNE plateforme avant d'en ouvrir une deuxième. Être partout = être nulle part."}, {"question": "Dans la stratégie Hub & Spoke, le HUB est...", "options": ["Instagram", "Votre Newsletter ou Site web", "TikTok", "LinkedIn"], "correct_index": 1, "explication": "Le HUB = la plateforme que vous POSSÉDEZ : Newsletter ou Site web."}, {"question": "Pourquoi la newsletter est-elle le HUB idéal ?", "options": ["Elle a le plus d'utilisateurs", "Aucun algorithme ne peut vous retirer votre audience", "Elle est gratuite", "Elle est facile à créer"], "correct_index": 1, "explication": "La newsletter est votre seul actif que vous possédez vraiment — aucun algorithme ne peut vous retirer votre audience."}, {"question": "Le SPOKE 1 dans la stratégie Hub & Spoke est...", "options": ["La plateforme de conversion", "La plateforme de découverte", "La plateforme de crédibilité", "Le site web"], "correct_index": 1, "explication": "SPOKE 1 = plateforme de découverte (Instagram, TikTok) qui attire de nouveaux followers."}, {"question": "Quel est le signal le plus fort pour les algorithmes ?", "options": ["Le nombre de followers", "L'engagement rate", "La fréquence de publication", "La qualité des images"], "correct_index": 1, "explication": "L'engagement rate est le signal le plus fort. 10% d'engagement bat 1% même avec 10x plus d'abonnés."}, {"question": "La performance d'un post dans les premiers combien de minutes décide de sa portée ?", "options": ["5-10 minutes", "30-60 minutes", "2-3 heures", "24 heures"], "correct_index": 1, "explication": "La performance dans les 30-60 premières minutes décide de la portée totale."}, {"question": "LinkedIn est idéal pour quelle tranche d'âge ?", "options": ["16-25 ans", "18-35 ans", "25-50 ans", "50+ ans"], "correct_index": 2, "explication": "LinkedIn : 25-50 ans, professionnel, texte long + carrousel, idéal pour décideurs et B2B."}, {"question": "TikTok est reconnu pour...", "options": ["Sa portée organique massive", "Son SEO durable", "Ses revenus directs", "Sa communauté B2B"], "correct_index": 0, "explication": "TikTok : portée organique massive, 16-30 ans, vidéo courte."}, {"question": "Dans la bio parfaite, quel est le 5ème élément ?", "options": ["Votre âge", "Un CTA — une seule action à faire", "Votre parcours complet", "Vos hobbies"], "correct_index": 1, "explication": "Bio : 1.Qui 2.Ce que vous faites 3.Preuve de crédibilité 4.Ce que vous offrez 5.CTA."}, {"question": "L'irrégularité de publication...", "options": ["N'a aucun impact", "Punit la portée", "Améliore l'algorithme", "Crée du mystère"], "correct_index": 1, "explication": "La consistance est une loi des algorithmes. L'irrégularité punit la portée."}, {"question": "Dans le cas d'Amine, quel était le principal problème de sa bio AVANT optimisation ?", "options": ["Elle était trop longue", "Elle manquait de cible, de résultat et de CTA clair", "Elle n'avait pas d'emoji", "Elle était en anglais"], "correct_index": 1, "explication": "La bio d'Amine était vague, sans cible précise, sans résultat mesurable et avec un CTA flou. Après optimisation avec la formule (Qui + Pour qui + Preuve + CTA), ses clics en bio ont augmenté significativement."}, {"question": "La priorité absolue dès le premier jour est de...", "options": ["Créer un logo", "Construire votre liste email", "Acheter de la publicité", "Créer un site web complexe"], "correct_index": 1, "explication": "Priorité absolue : construire votre liste email DÈS LE PREMIER JOUR."}, {"question": "YouTube est reconnu pour...", "options": ["Sa portée organique instantanée", "Son SEO durable et ses revenus directs", "Son audience très jeune", "Ses formats courts uniquement"], "correct_index": 1, "explication": "YouTube : SEO durable, revenus directs, tout âge, vidéo longue."}, {"question": "Le SPOKE 3 sert à...", "options": ["Attirer de nouveaux followers", "Renforcer l'autorité", "Qualifier et convertir les prospects chauds", "Créer du contenu viral"], "correct_index": 2, "explication": "SPOKE 3 = plateforme de conversion (DMs, groupe privé). Qualifie et convertit."}, {"question": "La rétention vidéo signifie...", "options": ["Combien de personnes ont vu la miniature", "Les vidéos vues jusqu'au bout sont boostées", "Le nombre de partages", "Le taux de like"], "correct_index": 1, "explication": "Rétention = vidéos vues jusqu'au bout = boostées par l'algorithme."}, {"question": "Le problème de la bio d'Amine AVANT était...", "options": ["Trop courte", "Vague, pas de cible, pas de résultat, CTA flou", "Trop technique", "Pas de photo"], "correct_index": 1, "explication": "La bio était vague, sans cible, sans résultat, avec un CTA flou."}, {"question": "Le podcast est idéal pour développer...", "options": ["La viralité", "L'intimité, la fidélité et l'autorité", "Les ventes rapides", "Le SEO"], "correct_index": 1, "explication": "Podcast : intimité, fidélité, autorité. 25-45 ans, audio 20-60 min."}, {"question": "Être partout équivaut à...", "options": ["Être visible", "Être crédible", "Être nulle part", "Être performant"], "correct_index": 2, "explication": "Être partout = être nulle part. Concentrez-vous sur une plateforme."}, {"question": "Instagram est idéal pour quelle tranche d'âge ?", "options": ["16-25 ans", "18-35 ans", "35-50 ans", "50+ ans"], "correct_index": 1, "explication": "Instagram : 18-35 ans, généraliste, Reels + Carousels."}, {"question": "Le SPOKE 2 sert à...", "options": ["Attirer de nouveaux followers", "Renforcer l'autorité pour les offres premium", "Convertir les prospects", "Créer du contenu viral"], "correct_index": 1, "explication": "SPOKE 2 = plateforme de crédibilité (LinkedIn, YouTube). Renforce l'autorité."}], "chapitre_id": "ea5c0a18-8dfb-4e73-ad17-131e012daebb"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 6 — Storytelling & Authenticité", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Combien d'éléments contient une histoire fondatrice puissante ?", "options": ["3", "4", "6", "8"], "correct_index": 2, "explication": "6 éléments : contexte, élément déclencheur, lutte, découverte, transformation, invitation."}, {"question": "Combien de types de stories récurrentes existe-t-il ?", "options": ["3", "5", "7", "10"], "correct_index": 2, "explication": "7 types : transformation, échec, valeurs, client, mentor, quotidienne, conviction."}, {"question": "Quel type de story est le plus puissant pour créer la connexion ?", "options": ["L'histoire de transformation", "L'histoire d'échec", "L'histoire du mentor", "L'histoire quotidienne"], "correct_index": 1, "explication": "L'histoire d'échec est la plus puissante pour créer la connexion humaine immédiate."}, {"question": "L'authenticité intelligente signifie...", "options": ["Tout montrer sans filtre", "Révéler intentionnellement qui vous êtes vraiment", "Cacher vos défauts", "Copier les autres"], "correct_index": 1, "explication": "L'authenticité intelligente = l'art de révéler intentionnellement qui vous êtes vraiment."}, {"question": "Les marques sans opinion sont des marques sans...", "options": ["Budget", "Audience", "Destin", "Contenu"], "correct_index": 2, "explication": "Les marques sans opinion sont des marques sans destin."}, {"question": "Confondre authenticité et oversharing est...", "options": ["Recommandé", "Une erreur à éviter", "Nécessaire pour créer la connexion", "La clé du succès"], "correct_index": 1, "explication": "NON à confondre authenticité et oversharing — tout montrer sans raison est une erreur."}, {"question": "L'histoire fondatrice explique...", "options": ["Votre parcours scolaire", "Pourquoi vous faites ce que vous faites", "Vos revenus", "Votre plan d'affaires"], "correct_index": 1, "explication": "L'histoire fondatrice est le récit qui explique pourquoi vous faites ce que vous faites."}, {"question": "L'histoire de VALEURS sert à...", "options": ["Attirer tout le monde", "Filtrer les mauvais clients", "Vendre plus", "Être viral"], "correct_index": 1, "explication": "L'histoire de valeurs filtre les mauvais clients en montrant vos principes."}, {"question": "Dans le cas de Hana, quel a été l'élément déclencheur ?", "options": ["Un licenciement", "Un burnout complet", "Un déménagement", "Une promotion"], "correct_index": 1, "explication": "En 2021, burnout complet. 3 semaines d'arrêt. Elle n'a pas pu se lever pendant 5 jours."}, {"question": "La découverte de Hana était que...", "options": ["Son boulot était trop dur", "L'absence de mission était le vrai problème", "Elle devait changer de secteur", "Elle avait besoin de plus d'argent"], "correct_index": 1, "explication": "'J'ai compris que ce n'était pas mon boulot le problème. C'était l'absence de mission.'"}, {"question": "L'histoire du CLIENT est la preuve sociale la plus...", "options": ["Facile à créer", "Puissante", "Risquée", "Courte"], "correct_index": 1, "explication": "L'histoire du client (transformation A à Z) est la preuve sociale la plus puissante."}, {"question": "Exposer des douleurs privées uniquement pour l'engagement est...", "options": ["De l'authenticité intelligente", "Un NON catégorique", "Recommandé pour le storytelling", "Nécessaire pour le personal branding"], "correct_index": 1, "explication": "NON : exposer des douleurs privées uniquement pour l'engagement n'est pas de l'authenticité."}, {"question": "Votre histoire n'a pas besoin d'être parfaite — elle doit être...", "options": ["Longue", "Dramatique", "Vraie", "Virale"], "correct_index": 2, "explication": "Votre histoire n'a pas besoin d'être parfaite — elle doit être vraie."}, {"question": "L'histoire QUOTIDIENNE relie...", "options": ["Deux événements dramatiques", "Un événement banal à un enseignement profond", "Votre passé à votre futur", "Deux clients entre eux"], "correct_index": 1, "explication": "L'histoire quotidienne = un événement banal relié à un enseignement profond."}, {"question": "L'INVITATION dans l'histoire fondatrice c'est...", "options": ["Vendre votre produit", "Ce que vous voulez pour votre audience", "Demander des likes", "Montrer vos résultats"], "correct_index": 1, "explication": "L'invitation = pourquoi vous partagez ça et ce que vous voulez pour votre audience."}, {"question": "L'histoire de CONVICTION est...", "options": ["Une croyance populaire", "Une croyance forte que vous défendez contre l'opinion commune", "Un témoignage client", "Un fait scientifique"], "correct_index": 1, "explication": "L'histoire de conviction = une croyance forte défendue contre l'opinion commune."}, {"question": "Partager vos vraies opinions même si elles sont impopulaires est...", "options": ["Dangereux", "De l'authenticité intelligente", "Interdit", "Du marketing agressif"], "correct_index": 1, "explication": "OUI : partager vos vraies opinions même si elles sont impopulaires fait partie de l'authenticité intelligente."}, {"question": "Votre histoire fondatrice est votre différenciateur le plus...", "options": ["Commercial", "Technique", "Unique", "Risqué"], "correct_index": 2, "explication": "Votre histoire fondatrice est votre différenciateur le plus unique. Personne n'a vécu exactement votre parcours."}, {"question": "Le CONTEXTE dans l'histoire fondatrice décrit...", "options": ["Votre situation actuelle", "Où en étiez-vous avant — votre vie ordinaire", "Votre plan d'action", "Vos objectifs futurs"], "correct_index": 1, "explication": "Le contexte = où en étiez-vous avant ? Quelle était votre vie 'ordinaire' ?"}, {"question": "L'histoire fondatrice est comparée au...", "options": ["Plan marketing", "Cœur émotionnel de votre personal brand", "Business plan", "CV en ligne"], "correct_index": 1, "explication": "L'histoire fondatrice est le cœur émotionnel de votre personal brand."}], "chapitre_id": "f7a9c939-89a1-4e7a-9a47-1964ecdbb483"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 7 — Communauté & Réseau", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quelle est la différence clé entre audience et communauté ?", "options": ["L'audience est plus grande", "L'audience regarde, la communauté participe", "Aucune différence", "La communauté est payante"], "correct_index": 1, "explication": "Une audience regarde. Une communauté participe, partage, défend et achète."}, {"question": "Quel est le taux de conversion d'une communauté vs une audience ?", "options": ["Audience 1-3% vs Communauté 10-30%", "Audience 10% vs Communauté 20%", "Audience 5% vs Communauté 50%", "Identique pour les deux"], "correct_index": 0, "explication": "Audience : conversion 1-3%. Communauté : conversion 10-30%."}, {"question": "Quel pourcentage de votre audience sont des observateurs ?", "options": ["50%", "75%", "95%", "99%"], "correct_index": 2, "explication": "Observateurs (95%) : lisent sans interagir. Les convertir en actifs = objectif n°1."}, {"question": "Les ambassadeurs représentent quel pourcentage ?", "options": ["0,1%", "0,4%", "1,5%", "3%"], "correct_index": 1, "explication": "Ambassadeurs (0,4%) : partagent et recommandent activement."}, {"question": "Comment faut-il répondre aux commentaires ?", "options": ["Avec un simple 'merci !'", "Avec substance, dans les premières heures", "Seulement aux commentaires positifs", "Une fois par semaine en batch"], "correct_index": 1, "explication": "Répondre à CHAQUE commentaire dans les premières heures — avec substance, pas juste 'merci !'."}, {"question": "Le networking stratégique sur 90 jours commence par...", "options": ["Envoyer des DM de pitch", "Identifier 20 créateurs de votre niche", "Lancer un podcast", "Créer un groupe privé"], "correct_index": 1, "explication": "Semaines 1-4 : identifier 20 créateurs de votre niche et commenter leurs posts."}, {"question": "Aux semaines 5-8 du networking, on doit envoyer...", "options": ["Des pitchs commerciaux", "Des DM de valeur sans pitch", "Des demandes de partenariat", "Des publicités"], "correct_index": 1, "explication": "Semaines 5-8 : DM de valeur (ressource utile, feedback sincère). Pas de pitch."}, {"question": "1 000 vraies relations valent plus que...", "options": ["10 000 followers", "50 000 followers", "100 000 followers passifs", "1 million d'impressions"], "correct_index": 2, "explication": "1 000 vraies relations valent plus que 100 000 followers passifs."}, {"question": "Quel outil est recommandé pour le monitoring de votre e-réputation ?", "options": ["Instagram Analytics", "Google Alerts", "Facebook Insights", "TikTok Creator Studio"], "correct_index": 1, "explication": "Configurez une alerte Google et cherchez votre nom régulièrement."}, {"question": "Si vous vous trompez publiquement, vous devez...", "options": ["Supprimer le post", "L'admettre clairement et rapidement", "Ignorer la situation", "Blâmer quelqu'un d'autre"], "correct_index": 1, "explication": "Admettez-le clairement et rapidement. La réaction à l'erreur dit plus que l'erreur elle-même."}, {"question": "Dans le cas de Youssef, quel résultat a-t-il obtenu à 90 jours ?", "options": ["10 clients payants", "1 000 abonnés", "3 lives croisés, +1 200 abonnés, 2 collaborations", "Un podcast lancé"], "correct_index": 2, "explication": "Résultat à 90 jours : 3 lives croisés, +1 200 nouveaux abonnés, 2 collaborations rémunérées."}, {"question": "Avant de publier une opinion forte, demandez-vous...", "options": ["Combien de likes ça va générer", "Pouvez-vous l'assumer dans 5 ans ?", "Est-ce que c'est tendance ?", "Est-ce que les concurrents le font ?"], "correct_index": 1, "explication": "Tout ce que vous publiez reste accessible. Pouvez-vous l'assumer dans 5 ans ?"}, {"question": "Les clients récurrents représentent quel pourcentage ?", "options": ["0,1%", "0,4%", "1,5%", "3%"], "correct_index": 0, "explication": "Clients récurrents (0,1%) : votre cœur économique."}, {"question": "Les commentateurs représentent quel pourcentage de l'audience ?", "options": ["0,1%", "0,4%", "1,5%", "3%"], "correct_index": 2, "explication": "Commentateurs (1,5%) : portent votre visibilité."}, {"question": "La cohérence entre offline et online est la fondation...", "options": ["De la viralité", "De la monétisation", "Indestructible de la réputation", "Du contenu"], "correct_index": 2, "explication": "La cohérence entre offline et online est la fondation indestructible de la réputation."}, {"question": "Aux semaines 9-12 du networking, on propose...", "options": ["Un partenariat commercial", "Une collaboration légère (interview, cross-post)", "Un investissement", "Un emploi"], "correct_index": 1, "explication": "Semaines 9-12 : proposer une collaboration légère. La relation est déjà établie."}, {"question": "Construire une communauté est...", "options": ["Optionnel", "La priorité absolue", "Moins important que le contenu", "Réservé aux grandes marques"], "correct_index": 1, "explication": "Construire une communauté = priorité absolue."}, {"question": "Ce que vous dites en ligne doit correspondre à...", "options": ["Ce que votre audience veut entendre", "Ce que vous faites en coulisses", "Ce que font vos concurrents", "Ce qui est tendance"], "correct_index": 1, "explication": "Cohérence : ce que vous dites en ligne doit correspondre à ce que vous faites en coulisses."}, {"question": "Votre réseau est comparé à...", "options": ["Un portefeuille", "Un filet de sécurité", "Un CV", "Un business plan"], "correct_index": 1, "explication": "Votre réseau = votre filet de sécurité."}, {"question": "Face aux critiques gratuites, la meilleure réaction est...", "options": ["Répondre avec énervement", "Ne pas répondre", "Bloquer immédiatement", "Faire un post public"], "correct_index": 1, "explication": "Répondez calmement et factuellement. Ou ne répondez pas si la critique est gratuite."}], "chapitre_id": "b6a389ca-e1b9-45ed-a6ff-e9e18357d130"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Module 8 — Autorité & Monétisation", "description": "20 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Combien de preuves de légitimité sont listées ?", "options": ["3", "5", "7", "10"], "correct_index": 2, "explication": "7 preuves : résultats, consistance, témoignages, médias, partenariats, profondeur, méthode propriétaire."}, {"question": "Ce que les autres disent de vous est combien de fois plus puissant que ce que vous dites ?", "options": ["2x", "5x", "10x", "20x"], "correct_index": 2, "explication": "Les témoignages : ce que les autres disent de vous est 10x plus puissant que ce que vous dites."}, {"question": "Combien de sources de revenus un personal brand peut-il avoir ?", "options": ["3", "5", "7", "10"], "correct_index": 3, "explication": "10 sources de revenus possibles pour un personal brand."}, {"question": "Le coaching 1-to-1 est...", "options": ["Scalable et low-ticket", "À marges élevées mais non scalable", "Passif et récurrent", "Le meilleur pour débuter"], "correct_index": 1, "explication": "Coaching 1-to-1 : marges élevées mais non scalable."}, {"question": "Le mid-ticket se situe dans quelle fourchette de prix ?", "options": ["7-97€", "100-997€", "1 000-10 000€", "10 000€+"], "correct_index": 1, "explication": "Mid-ticket (100-997€) : formation complète, programme groupe. Cœur économique."}, {"question": "Par quoi faut-il commencer selon le module ?", "options": ["Le high-ticket", "Le freemium", "Le mid-ticket", "Le low-ticket"], "correct_index": 2, "explication": "Commencez par le mid-ticket — le plus facile à vendre et le plus rentable."}, {"question": "La phase de VALIDATION dure...", "options": ["0-3 mois", "3-12 mois", "12+ mois", "24+ mois"], "correct_index": 0, "explication": "Validation (0-3 mois) : offrir à prix réduit contre témoignages détaillés."}, {"question": "Une méthode propriétaire doit avoir combien d'étapes essentielles ?", "options": ["1-2", "3-7", "8-10", "15+"], "correct_index": 1, "explication": "Identifiez les 3 à 7 étapes essentielles et distinctes de votre méthode."}, {"question": "L'affiliation consiste à...", "options": ["Créer des produits", "Toucher des commissions sur produits recommandés", "Sponsoriser des créateurs", "Vendre des formations"], "correct_index": 1, "explication": "Affiliation : commission sur produits recommandés. Zéro création produit."}, {"question": "N'avoir qu'une seule offre au mauvais prix est...", "options": ["Une bonne stratégie", "Une erreur classique", "Recommandé pour débuter", "La norme du marché"], "correct_index": 1, "explication": "N'avoir qu'une seule offre au mauvais prix = erreur classique."}, {"question": "Les semaines 1-2 du plan 90 jours correspondent à...", "options": ["Le lancement", "Les fondations", "La traction", "La monétisation"], "correct_index": 1, "explication": "Semaines 1-2 : FONDATIONS — questions fondatrices, avatar, positionnement, profil."}, {"question": "À quel moment lance-t-on la 1ère offre payante dans le plan 90 jours ?", "options": ["Semaine 1", "Semaine 3", "Semaine 7-12", "Après 6 mois"], "correct_index": 2, "explication": "Semaines 7-12 (TRACTION) : lancer votre 1ère offre payante."}, {"question": "Dans le cas de Bilal, combien de clients a-t-il eu à la semaine 12 ?", "options": ["0", "1", "3", "10"], "correct_index": 2, "explication": "Semaine 12 : 3 clients payants, liste email de 180 personnes, crédibilité établie."}, {"question": "Le prix de la première vente de Bilal était de...", "options": ["97€", "247€", "497€", "997€"], "correct_index": 2, "explication": "Semaine 9 : 1ère vente à 497€."}, {"question": "L'autorité par association signifie...", "options": ["Avoir beaucoup de diplômes", "S'associer à des marques ou experts reconnus", "Être vu à la télévision", "Avoir un bureau prestigieux"], "correct_index": 1, "explication": "Partenariats : s'associer à des marques ou experts reconnus (autorité par association)."}, {"question": "Le freemium (0€) sert d'...", "options": ["Objectif final", "Entrée dans l'écosystème", "Arnaque marketing", "Perte financière"], "correct_index": 1, "explication": "Freemium (0€) : contenu, lead magnet, webinaire. Entrée dans l'écosystème."}, {"question": "La phase SCALE commence à partir de...", "options": ["3 mois", "6 mois", "12 mois", "24 mois"], "correct_index": 2, "explication": "Scale (12 mois+) : automatiser, déléguer, multiplier les sources."}, {"question": "L'expertise perçue est...", "options": ["Moins importante que l'expertise réelle", "Aussi importante que l'expertise réelle", "Ce que les autres perçoivent que vous savez", "Un mensonge marketing"], "correct_index": 2, "explication": "L'expertise n'est pas seulement ce que vous savez — c'est ce que les autres perçoivent que vous savez."}, {"question": "Le post viral de Bilal à la semaine 5 a fait combien de vues ?", "options": ["1 000", "5 000", "15 000", "50 000"], "correct_index": 2, "explication": "Son post '5 outils gratuits qui m'ont fait gagner 12h/semaine' fait 15 000 vues."}, {"question": "Inventeur ≠ ...", "options": ["Créateur", "Imitateur", "Expert", "Leader"], "correct_index": 1, "explication": "Méthode propriétaire : donnez un nom à ce que vous faites. Inventeur ≠ imitateur."}], "chapitre_id": "d17a9be5-fdf8-47ab-bae4-751db8c68171"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Personal Branding — Validation Finale", "description": "30 questions (23 des modules + 7 transversales). Valide ce quiz pour finaliser la formation et débloquer le chapitre suivant de ton parcours.", "max_errors": 3, "status": "published", "questions": [{"question": "Quels sont les 3 piliers fondamentaux du personal branding ?", "options": ["Contenu, Audience, Revenus", "Identité, Visibilité, Crédibilité", "Logo, Couleurs, Typographie", "Stratégie, Exécution, Monétisation"], "correct_index": 1, "explication": "Les 3 piliers sont : Identité (qui vous êtes), Visibilité (être vu), Crédibilité (être cru et respecté)."}, {"question": "Quel est l'ordre correct de la pyramide du personal branding (du bas vers le haut) ?", "options": ["Contenu → Communauté → Monétisation → Clarté", "Clarté → Positionnement → Contenu → Communauté → Autorité → Monétisation", "Monétisation → Autorité → Contenu → Positionnement", "Visibilité → Crédibilité → Identité → Monétisation"], "correct_index": 1, "explication": "La pyramide se construit du bas vers le haut : Clarté → Positionnement → Contenu → Communauté → Autorité → Monétisation."}, {"question": "Votre personal brand existe déjà — la question est de savoir si vous le...", "options": ["Monétisez", "Contrôlez", "Copiez", "Ignorez"], "correct_index": 1, "explication": "Votre personal brand existe déjà — la question est de savoir si vous le contrôlez."}, {"question": "Quelle est la formule de positionnement en une phrase ?", "options": ["Je suis expert en [domaine]", "J'aide [cible] à [résultat] grâce à [méthode], même si [contrainte]", "Mon produit est le meilleur du marché", "Je vends [produit] à [prix]"], "correct_index": 1, "explication": "La formule est : J'aide [cible précise] à [résultat désiré] grâce à [méthode unique], même si [objection/contrainte]."}, {"question": "Combien d'archétypes devriez-vous combiner pour votre marque ?", "options": ["1 seul", "2 (principal + secondaire)", "3 minimum", "Le plus possible"], "correct_index": 1, "explication": "Combinez 2 archétypes (principal + secondaire) pour plus de profondeur."}, {"question": "Les 5 questions fondatrices sont comparées à...", "options": ["Un business plan", "Un GPS de votre marque", "Un CV", "Un portfolio"], "correct_index": 1, "explication": "Les 5 questions fondatrices sont le GPS de votre marque. Sans elles, tout le reste est aléatoire."}, {"question": "En combien de millisecondes votre identité visuelle communique-t-elle votre positionnement ?", "options": ["500", "200", "50", "1000"], "correct_index": 2, "explication": "L'identité visuelle communique votre positionnement en 50 millisecondes."}, {"question": "Quelle est la règle pour la palette de couleurs ?", "options": ["Utiliser au moins 5 couleurs", "1 couleur dominante (60-70%), 1-2 secondaires, 1 accent", "Toujours utiliser du bleu", "Changer de couleurs chaque mois"], "correct_index": 1, "explication": "1 couleur dominante (60-70%), 1-2 couleurs secondaires, 1 accent. Pas plus."}, {"question": "Votre actif visuel le plus important est...", "options": ["Votre logo", "Votre palette de couleurs", "Votre photo de profil", "Vos templates de posts"], "correct_index": 2, "explication": "Photo de profil : votre actif le plus important. Investissez dans une séance pro."}, {"question": "Quel pourcentage de contenu éducatif est recommandé ?", "options": ["10-15%", "20-25%", "35-40%", "50-60%"], "correct_index": 2, "explication": "Éducatif : 35-40% — démontrer l'expertise avec tips, frameworks, tutoriels."}, {"question": "La régularité bat la qualité.", "options": ["Vrai", "Faux"], "correct_index": 0, "explication": "Un contenu moyen publié régulièrement bat un contenu excellent publié rarement."}, {"question": "Le repurposing permet de transformer 1 idée en combien de contenus ?", "options": ["3", "5", "10", "20"], "correct_index": 2, "explication": "1 idée = 10 contenus grâce au repurposing."}, {"question": "La règle d'or des plateformes est...", "options": ["Être sur toutes les plateformes", "Maîtriser UNE plateforme avant d'en ouvrir une deuxième", "Changer de plateforme chaque trimestre", "Publier le même contenu partout"], "correct_index": 1, "explication": "Maîtrisez UNE plateforme avant d'en ouvrir une deuxième. Être partout = être nulle part."}, {"question": "Dans la stratégie Hub & Spoke, le HUB est...", "options": ["Instagram", "Votre Newsletter ou Site web", "TikTok", "LinkedIn"], "correct_index": 1, "explication": "Le HUB = la plateforme que vous POSSÉDEZ : Newsletter ou Site web."}, {"question": "Quel est le signal le plus fort pour les algorithmes ?", "options": ["Le nombre de followers", "L'engagement rate", "La fréquence de publication", "La qualité des images"], "correct_index": 1, "explication": "L'engagement rate est le signal le plus fort. 10% d'engagement bat 1% même avec 10x plus d'abonnés."}, {"question": "Combien d'éléments contient une histoire fondatrice puissante ?", "options": ["3", "4", "6", "8"], "correct_index": 2, "explication": "6 éléments : contexte, élément déclencheur, lutte, découverte, transformation, invitation."}, {"question": "Quel type de story est le plus puissant pour créer la connexion ?", "options": ["L'histoire de transformation", "L'histoire d'échec", "L'histoire du mentor", "L'histoire quotidienne"], "correct_index": 1, "explication": "L'histoire d'échec est la plus puissante pour créer la connexion humaine immédiate."}, {"question": "Votre histoire n'a pas besoin d'être parfaite — elle doit être...", "options": ["Longue", "Dramatique", "Vraie", "Virale"], "correct_index": 2, "explication": "Votre histoire n'a pas besoin d'être parfaite — elle doit être vraie."}, {"question": "Quelle est la différence clé entre audience et communauté ?", "options": ["L'audience est plus grande", "L'audience regarde, la communauté participe", "Aucune différence", "La communauté est payante"], "correct_index": 1, "explication": "Une audience regarde. Une communauté participe, partage, défend et achète."}, {"question": "1 000 vraies relations valent plus que...", "options": ["10 000 followers", "50 000 followers", "100 000 followers passifs", "1 million d'impressions"], "correct_index": 2, "explication": "1 000 vraies relations valent plus que 100 000 followers passifs."}, {"question": "Combien de sources de revenus un personal brand peut-il avoir ?", "options": ["3", "5", "7", "10"], "correct_index": 3, "explication": "10 sources de revenus possibles pour un personal brand."}, {"question": "Par quoi faut-il commencer selon le module ?", "options": ["Le high-ticket", "Le freemium", "Le mid-ticket", "Le low-ticket"], "correct_index": 2, "explication": "Commencez par le mid-ticket — le plus facile à vendre et le plus rentable."}, {"question": "Inventeur ≠ ...", "options": ["Créateur", "Imitateur", "Expert", "Leader"], "correct_index": 1, "explication": "Méthode propriétaire : donnez un nom à ce que vous faites. Inventeur ≠ imitateur."}, {"question": "Dans quel ordre logique devez-vous construire votre personal brand ?", "options": ["Contenu → Identité → Monétisation", "Identité → Visibilité → Crédibilité → Monétisation", "Monétisation → Contenu → Communauté", "Visibilité → Monétisation → Identité"], "correct_index": 1, "explication": "La pyramide du Module 1 et le plan 90 jours du Module 8 confirment : d'abord l'identité (M1-M2), puis la visibilité (M3-M5), la crédibilité (M6-M7), et enfin la monétisation (M8)."}, {"question": "Votre formule de positionnement (Module 2) doit être visible dans...", "options": ["Votre logo uniquement", "Votre bio optimisée (Module 5)", "Votre palette de couleurs", "Votre calendrier éditorial"], "correct_index": 1, "explication": "La formule 'J'aide [cible] à [résultat] grâce à [méthode]' du Module 2 doit se retrouver dans votre bio (Module 5 : Qui + Pour qui + Preuve + Offre + CTA)."}, {"question": "Pourquoi la newsletter (Module 5) est-elle essentielle AVANT de monétiser (Module 8) ?", "options": ["Parce qu'elle est gratuite", "Parce que c'est le seul actif que vous possédez vraiment", "Parce qu'elle génère des likes", "Parce que les algorithmes la favorisent"], "correct_index": 1, "explication": "Le Hub & Spoke (Module 5) dit que la newsletter est votre seul actif non contrôlé par un algorithme. Le Module 8 confirme : sans liste email, pas de monétisation durable."}, {"question": "Les archétypes de marque (Module 2) influencent directement...", "options": ["Votre prix de vente", "Votre voix de marque et votre ton (Module 3)", "Le nombre de plateformes à utiliser", "Votre calendrier éditorial"], "correct_index": 1, "explication": "Vos archétypes (Sage, Héros, Rebelle...) du Module 2 déterminent votre voix de marque du Module 3 : ton, registre, rythme et personnalité."}, {"question": "Pour obtenir des témoignages (Module 8), il faut d'abord avoir construit...", "options": ["Un logo professionnel", "Un site web complet", "Une communauté engagée (Module 7) et une offre testée", "Un podcast"], "correct_index": 2, "explication": "Les témoignages (preuve de crédibilité, M8) viennent après avoir construit une communauté (M7) et proposé des sessions gratuites. La pyramide du M1 confirme : communauté avant monétisation."}, {"question": "Si votre diagnostic (Module 1) donne Identité 3/10, Visibilité 7/10, Crédibilité 6/10, quelle est l'action prioritaire ?", "options": ["Publier plus de contenu (visibilité)", "Obtenir des témoignages (crédibilité)", "Revenir aux 5 questions fondatrices (identité, Module 2)", "Lancer une offre payante (monétisation, Module 8)"], "correct_index": 2, "explication": "Le pilier le plus faible est l'Identité (3/10). Avant de poster ou vendre, il faut revenir aux fondamentaux du Module 2 : les 5 questions fondatrices, l'Ikigai et le positionnement."}, {"question": "Le repurposing (Module 4) combiné à la stratégie Hub & Spoke (Module 5) permet de...", "options": ["Publier le même contenu partout", "Créer 1 contenu source sur le Hub puis le décliner sur les Spokes", "Abandonner les réseaux sociaux", "Publier uniquement des newsletters"], "correct_index": 1, "explication": "Le repurposing (1 idée = 10 formats, M4) s'applique naturellement au Hub & Spoke (M5) : créez l'article source sur votre Hub (newsletter), puis déclinez en carousel IG, reel TikTok, post LinkedIn, etc."}], "formation_id": "d31a7726-6468-44ca-b07c-847e29b43ebc"}$quiz$::jsonb);

